endpoint.response:
{ success:true, message, data: Company, permissions: ResourcePermissions }
Company = {
  id:int, denomination:string, vat_number:string|null,
  address: {
    id:int, label:string|null, line1:string, line2:string|null, postal_code:string|null,
    country_id:int|null, state_id:int|null, province_id:int|null, city_id:int|null,
    country:string|null, region:string|null, province:string|null, city:string|null,
    is_primary:bool
  } | null,
  created_at:string|null
}
ResourcePermissions = {
  resource: { view,create,update,delete,export,import : bool },
  fields: { [key]: {visible,hidden,editable,readonly,required,disabled:bool} },
  actions: { [key]: bool }
}
fields keys = denomination, vat_number, address
actions keys = delete, export, import

endpoint.request:
body: {
  denomination:string (required, max:255),
  vat_number?:string|null (max:50),
  address?: {
    label?:string|null, line1:string (required se address presente, max:255), line2?:string|null,
    postal_code?:string|null (max:20),
    country_id?:int|null (exists:countries), state_id?:int|null (exists:states),
    province_id?:int|null (exists:provinces), city_id?:int|null (exists:cities)
  }
}
